#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum QuickFilterState {
    Open,
    Closed,
    Merged,
    Draft,
    All,
}

impl QuickFilterState {
    fn parse(value: &str) -> Option<Self> {
        match value.trim().to_ascii_lowercase().as_str() {
            "open" => Some(Self::Open),
            "closed" | "close" => Some(Self::Closed),
            "merged" => Some(Self::Merged),
            "draft" => Some(Self::Draft),
            "all" => Some(Self::All),
            _ => None,
        }
    }

    fn display(self) -> &'static str {
        match self {
            Self::Open => "open",
            Self::Closed => "closed",
            Self::Merged => "merged",
            Self::Draft => "draft",
            Self::All => "all",
        }
    }

    fn query_token(self) -> Option<&'static str> {
        match self {
            Self::Open => Some("is:open"),
            Self::Closed => Some("is:closed"),
            Self::Merged => Some("is:merged"),
            Self::Draft => Some("is:draft"),
            Self::All => None,
        }
    }
}

#[derive(Debug, Clone, Default, PartialEq, Eq)]
struct QuickFilter {
    state: Option<QuickFilterState>,
    assignee: Option<String>,
    author: Option<String>,
    labels: Vec<String>,
}

impl QuickFilter {
    fn parse(input: &str) -> std::result::Result<Option<Self>, String> {
        let input = input.trim();
        if input.is_empty() || matches!(input, "clear" | "reset") {
            return Ok(None);
        }

        let mut filter = Self::default();
        for token in input.split_whitespace() {
            if let Some(state) = QuickFilterState::parse(token) {
                filter.state = Some(state);
                continue;
            }
            if let Some(value) = token
                .strip_prefix("state:")
                .or_else(|| token.strip_prefix("is:"))
            {
                filter.state = Some(
                    QuickFilterState::parse(value)
                        .ok_or_else(|| format!("unknown state filter: {value}"))?,
                );
                continue;
            }
            if let Some(value) = token.strip_prefix("assignee:") {
                filter.assignee = Some(non_empty_filter_value("assignee", value)?);
                continue;
            }
            if let Some(value) = token.strip_prefix("author:") {
                filter.author = Some(non_empty_filter_value("author", value)?);
                continue;
            }
            if let Some(value) = token
                .strip_prefix("label:")
                .or_else(|| token.strip_prefix("labels:"))
            {
                for label in comma_separated_filter_values("label", value)? {
                    if !filter.labels.contains(&label) {
                        filter.labels.push(label);
                    }
                }
                continue;
            }

            return Err(format!("unknown filter token: {token}"));
        }

        Ok(Some(filter))
    }

    fn display(&self) -> String {
        let mut tokens = Vec::new();
        if let Some(state) = self.state {
            tokens.push(format!("state:{}", state.display()));
        }
        if let Some(assignee) = &self.assignee {
            tokens.push(format!("assignee:{assignee}"));
        }
        if let Some(author) = &self.author {
            tokens.push(format!("author:{author}"));
        }
        tokens.extend(self.labels.iter().map(|label| format!("label:{label}")));
        tokens.join(" ")
    }
}

fn non_empty_filter_value(name: &str, value: &str) -> std::result::Result<String, String> {
    let value = value.trim();
    if value.is_empty() {
        Err(format!("{name} filter is empty"))
    } else {
        Ok(value.to_string())
    }
}

fn comma_separated_filter_values(
    name: &str,
    value: &str,
) -> std::result::Result<Vec<String>, String> {
    let values = value
        .split(',')
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
        .collect::<Vec<_>>();
    if values.is_empty() {
        Err(format!("{name} filter is empty"))
    } else {
        Ok(values)
    }
}

fn quick_filter_query(base_filters: &str, filter: &QuickFilter) -> String {
    if base_filters.contains(" | ") {
        return base_filters
            .split(" | ")
            .map(|filters| quick_filter_query(filters, filter))
            .collect::<Vec<_>>()
            .join(" | ");
    }

    let base_tokens = base_filters
        .split_whitespace()
        .filter(|token| !quick_filter_replaces_token(token, filter))
        .map(str::to_string)
        .collect::<Vec<_>>();
    let overlay_tokens = quick_filter_tokens(filter);
    insert_tokens_before_sort(base_tokens, overlay_tokens).join(" ")
}

fn quick_filter_replaces_token(token: &str, filter: &QuickFilter) -> bool {
    (filter.state.is_some() && is_state_filter_token(token))
        || (filter.assignee.is_some() && token.starts_with("assignee:"))
        || (filter.author.is_some() && token.starts_with("author:"))
        || (!filter.labels.is_empty()
            && (token.starts_with("label:") || token.starts_with("labels:")))
}

fn quick_filter_tokens(filter: &QuickFilter) -> Vec<String> {
    let mut tokens = Vec::new();
    if let Some(token) = filter.state.and_then(QuickFilterState::query_token) {
        tokens.push(token.to_string());
    }
    if let Some(assignee) = &filter.assignee {
        tokens.push(format!("assignee:{assignee}"));
    }
    if let Some(author) = &filter.author {
        tokens.push(format!("author:{author}"));
    }
    tokens.extend(filter.labels.iter().map(|label| format!("label:{label}")));
    tokens
}

fn insert_tokens_before_sort(
    mut base_tokens: Vec<String>,
    overlay_tokens: Vec<String>,
) -> Vec<String> {
    if overlay_tokens.is_empty() {
        return base_tokens;
    }
    let sort_index = base_tokens
        .iter()
        .position(|token| token.starts_with("sort:"))
        .unwrap_or(base_tokens.len());
    base_tokens.splice(sort_index..sort_index, overlay_tokens);
    base_tokens
}

fn is_state_filter_token(token: &str) -> bool {
    matches!(
        token,
        "is:open" | "is:closed" | "is:merged" | "is:draft" | "draft:true" | "draft:false"
    ) || token.starts_with("state:")
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum RefreshPriority {
    User,
    Background,
}

pub async fn run(mut config: Config, paths: Paths, store: SnapshotStore) -> Result<()> {
    let cached = store.load_all()?;
    let show_startup_dialog = should_show_startup_dialog(&cached);
    let sections = merge_cached_sections(configured_sections(&config), cached);
    let repo_candidate_cache = store.load_repo_candidate_cache()?;
    let ui_state = UiState::load_or_default(&paths.state_path);
    let mut app = AppState::with_ui_state(config.defaults.view, sections, ui_state);
    app.load_repo_candidate_cache(repo_candidate_cache);
    app.command_palette_key = normalized_command_palette_key(&config.defaults.command_palette_key);
    let startup_setup_dialog = startup_setup_dialog();
    if let Some(dialog) = startup_setup_dialog {
        app.show_setup_dialog(dialog);
    } else if show_startup_dialog {
        app.show_startup_initializing();
    }

    let (tx, mut rx) = mpsc::unbounded_channel();
    if startup_setup_dialog.is_none() {
        start_refresh(
            config.clone(),
            store.clone(),
            tx.clone(),
            RefreshPriority::Background,
        );
    }

    enable_raw_mode()?;
    let mut stdout = io::stdout();
    execute!(
        stdout,
        EnterAlternateScreen,
        EnableMouseCapture,
        PushKeyboardEnhancementFlags(
            KeyboardEnhancementFlags::DISAMBIGUATE_ESCAPE_CODES
                | KeyboardEnhancementFlags::REPORT_EVENT_TYPES
        )
    )?;
    let backend = CrosstermBackend::new(stdout);
    let mut terminal = Terminal::new(backend)?;

    let result = run_loop(
        &mut terminal,
        &mut app,
        &mut config,
        &paths,
        &store,
        &tx,
        &mut rx,
    )
    .await;

    disable_raw_mode()?;
    execute!(
        terminal.backend_mut(),
        PopKeyboardEnhancementFlags,
        DisableMouseCapture,
        LeaveAlternateScreen
    )?;
    terminal.show_cursor()?;

    result
}

fn should_show_startup_dialog(cached: &HashMap<String, SectionSnapshot>) -> bool {
    cached.is_empty()
}

fn startup_setup_dialog() -> Option<SetupDialog> {
    startup_setup_dialog_from_gh_probe(
        Command::new("gh")
            .env("GH_PROMPT_DISABLED", "1")
            .arg("--version")
            .output()
            .map(|_| ()),
    )
}

fn startup_setup_dialog_from_gh_probe(result: io::Result<()>) -> Option<SetupDialog> {
    match result {
        Ok(()) => None,
        Err(error) if error.kind() == io::ErrorKind::NotFound => Some(SetupDialog::MissingGh),
        Err(_) => None,
    }
}

async fn run_loop(
    terminal: &mut Terminal<CrosstermBackend<io::Stdout>>,
    app: &mut AppState,
    config: &mut Config,
    paths: &Paths,
    store: &SnapshotStore,
    tx: &UnboundedSender<AppMsg>,
    rx: &mut UnboundedReceiver<AppMsg>,
) -> Result<()> {
    let mut mouse_capture_enabled = true;
    loop {
        while let Ok(message) = rx.try_recv() {
            app.handle_msg(message);
        }
        app.ensure_current_details_loading(tx);
        app.ensure_current_diff_loading(tx);
        app.dismiss_expired_message_dialog(Instant::now());

        if !app.refreshing
            && config.defaults.refetch_interval_seconds > 0
            && app.last_refresh_request.elapsed().as_secs()
                >= config.defaults.refetch_interval_seconds
        {
            start_refresh(
                config.clone(),
                store.clone(),
                tx.clone(),
                RefreshPriority::Background,
            );
        }

        terminal.draw(|frame| draw(frame, app, paths))?;

        let mut should_quit = false;
        if event::poll(Duration::from_millis(120))? {
            let events = read_event_batch(event::read()?)?;
            let size = terminal.size()?;
            let area = Rect::new(0, 0, size.width, size.height);
            should_quit = handle_event_batch_mut(app, events, area, config, paths, store, tx);
        }
        sync_mouse_capture(terminal, app, &mut mouse_capture_enabled)?;
        if should_quit {
            break;
        }
    }

    save_ui_state(app, paths);
    Ok(())
}

fn read_event_batch(first: Event) -> Result<Vec<Event>> {
    let mut events = vec![first];
    while events.len() < EVENT_BATCH_LIMIT && event::poll(Duration::from_millis(0))? {
        events.push(event::read()?);
    }
    Ok(events)
}

fn handle_event_batch_mut(
    app: &mut AppState,
    events: Vec<Event>,
    area: Rect,
    config: &mut Config,
    paths: &Paths,
    store: &SnapshotStore,
    tx: &UnboundedSender<AppMsg>,
) -> bool {
    let mut pending_scroll = None;

    for event in events {
        match event {
            Event::Key(key) => {
                flush_pending_mouse_scroll(app, &mut pending_scroll);
                if key.kind == KeyEventKind::Release {
                    continue;
                }
                if handle_key_in_area_mut(app, key, config, paths, store, tx, Some(area)) {
                    save_ui_state(app, paths);
                    return true;
                }
            }
            Event::Mouse(mouse) => {
                if try_accumulate_mouse_scroll(app, mouse, area, &mut pending_scroll) {
                    continue;
                }
                flush_pending_mouse_scroll(app, &mut pending_scroll);
                if handle_mouse_with_sync(app, mouse, area, Some(store), Some(tx)) {
                    save_ui_state(app, paths);
                }
            }
            _ => flush_pending_mouse_scroll(app, &mut pending_scroll),
        }
    }

    flush_pending_mouse_scroll(app, &mut pending_scroll);
    false
}

#[cfg(test)]
fn handle_event_batch(
    app: &mut AppState,
    events: Vec<Event>,
    area: Rect,
    config: &Config,
    paths: &Paths,
    store: &SnapshotStore,
    tx: &UnboundedSender<AppMsg>,
) -> bool {
    let mut config = config.clone();
    handle_event_batch_mut(app, events, area, &mut config, paths, store, tx)
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum MouseWheelTargetKind {
    CommentDialog,
    List,
    Details,
}

#[derive(Debug, Clone, Copy)]
struct MouseWheelTarget {
    kind: MouseWheelTargetKind,
    area: Rect,
}

#[derive(Debug, Clone, Copy)]
struct PendingMouseScroll {
    target: MouseWheelTarget,
    steps: i16,
}

fn try_accumulate_mouse_scroll(
    app: &AppState,
    mouse: MouseEvent,
    area: Rect,
    pending: &mut Option<PendingMouseScroll>,
) -> bool {
    let Some(step) = mouse_scroll_step(mouse.kind) else {
        return false;
    };
    let Some(target) = mouse_wheel_target(app, mouse, area) else {
        return false;
    };

    match pending {
        Some(pending_scroll) if pending_scroll.target.kind == target.kind => {
            pending_scroll.steps = pending_scroll.steps.saturating_add(step);
        }
        Some(_) => {
            // The caller will flush and re-process this event as a normal mouse event.
            return false;
        }
        None => {
            *pending = Some(PendingMouseScroll {
                target,
                steps: step,
            });
        }
    }
    true
}

fn flush_pending_mouse_scroll(app: &mut AppState, pending: &mut Option<PendingMouseScroll>) {
    let Some(scroll) = pending.take() else {
        return;
    };
    let steps = scroll.steps.clamp(
        -MAX_COALESCED_MOUSE_SCROLL_STEPS,
        MAX_COALESCED_MOUSE_SCROLL_STEPS,
    );
    if steps == 0 {
        return;
    }

    match scroll.target.kind {
        MouseWheelTargetKind::CommentDialog => app.scroll_comment_dialog(
            steps.saturating_mul(MOUSE_COMMENT_SCROLL_LINES as i16),
            Some(scroll.target.area),
        ),
        MouseWheelTargetKind::List => handle_list_scroll(
            app,
            scroll.target.area,
            mouse_list_scroll_delta(app, steps as isize),
        ),
        MouseWheelTargetKind::Details => handle_details_scroll(
            app,
            scroll.target.area,
            steps.saturating_mul(MOUSE_DETAILS_SCROLL_LINES as i16),
        ),
    }
}

fn mouse_scroll_step(kind: MouseEventKind) -> Option<i16> {
    match kind {
        MouseEventKind::ScrollDown => Some(1),
        MouseEventKind::ScrollUp => Some(-1),
        _ => None,
    }
}

fn mouse_wheel_target(app: &AppState, mouse: MouseEvent, area: Rect) -> Option<MouseWheelTarget> {
    if !app.mouse_capture_enabled
        || app.setup_dialog.is_some()
        || app.startup_dialog.is_some()
        || app.command_palette.is_some()
        || app.project_switcher.is_some()
        || app.project_remove_dialog.is_some()
        || app.help_dialog
        || app.message_dialog.is_some()
        || app.item_edit_dialog.is_some()
        || app.pr_action_dialog.is_some()
        || app.label_dialog.is_some()
        || app.issue_dialog.is_some()
        || app.milestone_dialog.is_some()
        || app.assignee_dialog.is_some()
        || app.reviewer_dialog.is_some()
    {
        return None;
    }

    if let Some(dialog) = &app.comment_dialog {
        let dialog_area = comment_dialog_area(dialog, area);
        return rect_contains(dialog_area, mouse.column, mouse.row).then_some(MouseWheelTarget {
            kind: MouseWheelTargetKind::CommentDialog,
            area,
        });
    }

    let page = page_areas(area);
    let body_area = page[2];
    let body = body_areas_with_ratio(body_area, app.list_width_percent);
    let table = body[0];
    let details = body[1];
    if rect_contains(table, mouse.column, mouse.row) {
        Some(MouseWheelTarget {
            kind: MouseWheelTargetKind::List,
            area: table,
        })
    } else if rect_contains(details, mouse.column, mouse.row) {
        Some(MouseWheelTarget {
            kind: MouseWheelTargetKind::Details,
            area: details,
        })
    } else {
        None
    }
}

fn sync_mouse_capture(
    terminal: &mut Terminal<CrosstermBackend<io::Stdout>>,
    app: &AppState,
    enabled: &mut bool,
) -> Result<()> {
    if *enabled == app.mouse_capture_enabled {
        return Ok(());
    }

    if app.mouse_capture_enabled {
        execute!(terminal.backend_mut(), EnableMouseCapture)?;
    } else {
        execute!(terminal.backend_mut(), DisableMouseCapture)?;
    }
    *enabled = app.mouse_capture_enabled;
    Ok(())
}

fn start_refresh(
    config: Config,
    store: SnapshotStore,
    tx: UnboundedSender<AppMsg>,
    priority: RefreshPriority,
) {
    let _ = tx.send(AppMsg::RefreshStarted);
    tokio::spawn(async move {
        let mut save_error = None;
        let refresh = async {
            refresh_dashboard_with_progress(&config, |section| {
                if save_error.is_none()
                    && section.error.is_none()
                    && let Err(error) = store.save_section(section)
                {
                    let message = error.to_string();
                    warn!(error = %message, "failed to save refreshed snapshot");
                    save_error = Some(message);
                }

                let _ = tx.send(AppMsg::RefreshSectionLoaded {
                    section: section.clone(),
                    save_error: save_error.clone(),
                });
            })
            .await
        };
        let sections = match priority {
            RefreshPriority::User => refresh.await,
            RefreshPriority::Background => with_background_github_priority(refresh).await,
        };
        let _ = tx.send(AppMsg::RefreshFinished {
            sections,
            save_error,
        });
    });
}

fn start_section_page_load(
    app: &mut AppState,
    config: &Config,
    store: &SnapshotStore,
    tx: &UnboundedSender<AppMsg>,
    delta: isize,
) {
    if app.refreshing {
        app.status = "refresh already running".to_string();
        return;
    }

    let request = match app.section_page_request(delta, config) {
        Ok(request) => request,
        Err(message) => {
            app.status = message;
            return;
        }
    };
    let page_label =
        section_page_status_label(request.page, request.total_pages, request.total_is_capped);
    app.refreshing = true;
    app.last_refresh_request = Instant::now();
    app.status = format!("loading {} page {page_label}", request.title);

    let config = config.clone();
    let store = store.clone();
    let tx = tx.clone();
    tokio::spawn(async move {
        let section = refresh_section_page(
            request.view,
            request.kind,
            request.title,
            request.filters,
            request.page,
            request.page_size,
            &config,
        )
        .await;
        let mut save_error = None;
        if section.error.is_none()
            && let Err(error) = store.save_section(&section)
        {
            let message = error.to_string();
            warn!(error = %message, "failed to save paged snapshot");
            save_error = Some(message);
        }
        let _ = tx.send(AppMsg::SectionPageLoaded {
            section_key: request.section_key,
            section,
            save_error,
        });
    });
}

fn start_filtered_section_load(
    app: &mut AppState,
    config: &Config,
    tx: &UnboundedSender<AppMsg>,
    filter: Option<QuickFilter>,
) {
    let Some(section) = app.current_section() else {
        app.status = "no section selected".to_string();
        return;
    };
    if !matches!(
        section.kind,
        SectionKind::PullRequests | SectionKind::Issues
    ) {
        app.status = "quick filters are available for PR and issue sections".to_string();
        return;
    }

    let section_key = section.key.clone();
    let view = section_view_key(section);
    let kind = section.kind;
    let title = section.title.clone();
    let base_filters = app.base_filters_for_section(section);
    let page_size = section_page_size(section, config);
    let effective_filters = match &filter {
        Some(filter) => quick_filter_query(&base_filters, filter),
        None => base_filters.clone(),
    };
    let status_filter = filter.as_ref().map(QuickFilter::display);

    match filter {
        Some(filter) => {
            app.quick_filters.insert(section_key.clone(), filter);
        }
        None => {
            app.quick_filters.remove(&section_key);
        }
    }

    app.refreshing = true;
    app.last_refresh_request = Instant::now();
    app.set_current_selected_position(0);
    app.clear_current_list_scroll_offset();
    app.details_scroll = 0;
    app.selected_comment_index = 0;
    app.comment_dialog = None;
    app.pr_action_dialog = None;
    app.status = match status_filter {
        Some(filter) if !filter.is_empty() => format!("applying filter {filter}"),
        _ => "clearing quick filter".to_string(),
    };

    let config = config.clone();
    let tx = tx.clone();
    tokio::spawn(async move {
        let section =
            refresh_section_page(view, kind, title, effective_filters, 1, page_size, &config).await;
        let _ = tx.send(AppMsg::FilterSectionLoaded {
            section_key,
            section,
        });
    });
}

